import { Card } from '../ui/Card';

const KpiGrid = ({ kpis }) => {
  return (
    <div className="grid grid-cols-4 gap-4 mb-8">
      <Card title="Planificación">
        <div className="space-y-1 text-[11px] font-bold">
          <p>Proyectado: <span className="text-white ml-2">{kpis.proyectado}</span></p>
          <p>Arribado: <span className="text-orange-400 ml-4">{kpis.arribado}</span></p>
          <p className="text-blue-400 text-[10px] mt-2">AVANCE: {kpis.pArribado}%</p>
        </div>
      </Card>

      <Card title="Producción">
        <div className="space-y-1 text-[11px] font-bold">
          <p>Bipeado: <span className="text-white ml-2">{kpis.bipeado}</span></p>
          <p>Delta: <span className="text-[#ffab00] ml-4">{kpis.arribadoBipeado}</span></p>
        </div>
      </Card>

      {/* Agregamos más Cards según tu Excel... */}
    </div>
  );
};

export default KpiGrid;
